import React from 'react';
import { CSidebar, CSidebarNav, CNavItem } from '@coreui/react';
import CIcon from '@coreui/icons-react';
import SimpleBar from 'simplebar-react';
import 'simplebar/dist/simplebar.min.css';
import navigation from '../SideBar/LeftPanel/index'; // Your nav items

const SideBar = ({ sidebarShow, setSidebarShow }) => {
  return (
    <CSidebar
      position="fixed"
      visible={sidebarShow}
      onVisibleChange={setSidebarShow}
      className="c-sidebar"
    >
      <CSidebarNav>
        <SimpleBar style={{ maxHeight: '100vh' }}>
          {navigation.map((item, index) => {
            const { component: Component, name, to, icon } = item;
            return (
              <Component
                key={index}
                to={to}
                className={({ isActive }) =>
                  `nav-link ${isActive ? 'active' : ''}`
                }
              >
                <div className="nav-icon">{icon}</div>
                {name}
              </Component>
            );
          })}
        </SimpleBar>
      </CSidebarNav>
    </CSidebar>
  );
};

export default SideBar;
